#include <bits/stdc++.h>
using namespace std;

int max_complete_layers(int N) {
    int left = 0, right = N, result = 0;

    while (left <= right) {
        int mid = left + (right - left) / 2;
        long long total_bricks = (long long)mid * (mid + 1) / 2;

        if (total_bricks <= N) {
            result = mid;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }
    return result;
}

int main() {
    int T;
    cin >> T;

    while (T--) {
        int N;
        cin >> N;
        cout << max_complete_layers(N) << endl;
    }

    return 0;
}

