function maxCompleteLayers(N) {
    let left = 0, right = N, result = 0;

    while (left <= right) {
        let mid = Math.floor((left + right) / 2);
        let totalBricks = (mid * (mid + 1)) / 2;

        if (totalBricks <= N) {
            result = mid;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }
    return result;
}

